import{C as o,o as n,c as i,a5 as a,E as t}from"./chunks/framework.CW28V7p_.js";const m=JSON.parse('{"title":"6. Compression & cNFTs","description":"","frontmatter":{},"headers":[],"relativePath":"module-10/6-compression-nfts.md","filePath":"module-10/6-compression-nfts.md","lastUpdated":1780937944000}'),l={name:"module-10/6-compression-nfts.md"},u=Object.assign(l,{setup(c){const s={id:"m10-6-compression",title:"🧠 Mini-check: Compression",intro:"2 питання.",questions:[{type:"mcq",q:"Чому compression critical для NFT scaling?",options:["Standard NFT: ~0.012 SOL each для rent + metadata. 1M NFTs = 12,000 SOL impossible","Compressed NFT: ~0.00001 SOL each. 1M NFTs = 10 SOL feasible","Compression uses Merkle trees — store hash of millions tokens у single account","Same DEX trading works for both compressed/standard"],correct:[0,1,2,3],explanation:"Compression dramatically reduces cost. Trading abstracted by tooling. Module 10.6."},{type:"explain",q:"Як compression (cNFTs) works on high level?",ideal:`Standard NFT: each NFT = individual on-chain account (mint + metadata + ATA per owner). Costs add up.

Compressed NFT (cNFT): use **state compression** via Merkle trees:
1. Single Merkle tree account stores root hash представляє up to billion+ NFTs
2. Individual NFT data stored OFF-CHAIN (IPFS, Arweave) + proof tree position
3. Operations (transfer, sell) update Merkle root via tree proof
4. RPC indexers cache off-chain data, serve до wallets/marketplaces

Result:
- Cost: ~0.00001 SOL per NFT (1000x cheaper than standard)
- Trade-off: proof needed для each operation
- Trust: RPC providers reliable

Use cases: gaming NFTs (millions of items), loyalty programs, ticketing, identity badges.

Major platforms (Magic Eden, Tensor) support cNFTs natively now.`,explanation:"Module 10.6."}]};return(p,e)=>{const r=o("Quiz");return n(),i("div",null,[e[0]||(e[0]=a(`<h1 id="_6-compression-cnfts" tabindex="-1">6. Compression &amp; cNFTs <a class="header-anchor" href="#_6-compression-cnfts" aria-label="Permalink to &quot;6. Compression &amp; cNFTs&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>State compression</strong> — Solana technique storing data у Merkle trees замість individual accounts. <strong>cNFTs</strong> (compressed NFTs) — primary use case, reducing cost від ~0.012 SOL per NFT до ~0.00001 SOL (1000x cheaper). Enables million-scale NFT collections impossible раніше.</p><h2 id="why-compression" tabindex="-1">Why compression <a class="header-anchor" href="#why-compression" aria-label="Permalink to &quot;Why compression&quot;">​</a></h2><p>Standard SPL NFT (Module 2.4):</p><ul><li>Mint account: ~0.0015 SOL rent</li><li>Metadata account: ~0.005 SOL rent</li><li>ATA for each owner: ~0.002 SOL rent</li></ul><p>Per NFT ≈ 0.0085 SOL + metadata. 1M NFTs = ~8,500 SOL ($~1.7M at $200/SOL). Не feasible для large collections.</p><p>cNFT cost: ~0.00001 SOL per NFT. 1M NFTs = 10 SOL ($2,000). Affordable.</p><h2 id="merkle-tree-mechanism" tabindex="-1">Merkle tree mechanism <a class="header-anchor" href="#merkle-tree-mechanism" aria-label="Permalink to &quot;Merkle tree mechanism&quot;">​</a></h2><p><strong>Merkle tree</strong> — binary tree з hash combinations:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    Root hash</span></span>
<span class="line"><span>                   /         \\</span></span>
<span class="line"><span>              Hash(A,B)     Hash(C,D)</span></span>
<span class="line"><span>              /    \\         /    \\</span></span>
<span class="line"><span>          Hash A  Hash B  Hash C  Hash D</span></span>
<span class="line"><span>            |      |       |       |</span></span>
<span class="line"><span>          NFT 1  NFT 2  NFT 3  NFT 4</span></span></code></pre></div><p>On-chain: tree account stores <strong>only root hash + tree metadata</strong>. Compact representation.</p><p>Off-chain: each NFT&#39;s actual data (image URL, attributes, owner) lives у indexer database/IPFS.</p><p>Operations:</p><ul><li><strong>Mint</strong>: append NFT to tree, update root hash</li><li><strong>Transfer</strong>: provide Merkle proof + new owner, recompute root</li><li><strong>Sell</strong>: similar, з marketplace logic</li></ul><p>Costs:</p><ul><li>Tree account once: ~0.5 SOL (variable based on capacity)</li><li>Per NFT mint: minimal (just tree update)</li><li>Per transfer: minimal</li></ul><p>Capacity examples:</p><ul><li>Tree depth 14, branching factor 8 = ~16k NFTs, cost ~0.5 SOL setup</li><li>Tree depth 20, larger = millions NFTs, larger setup</li></ul><h2 id="rpc-indexer-dependency" tabindex="-1">RPC indexer dependency <a class="header-anchor" href="#rpc-indexer-dependency" aria-label="Permalink to &quot;RPC indexer dependency&quot;">​</a></h2><p>Critical implication: cNFT operations require <strong>off-chain index</strong>:</p><ul><li>RPC provider runs indexer caching off-chain NFT data + Merkle proofs</li><li>Wallets/marketplaces query indexer для display NFTs</li><li>Trust assumption: indexer accurate</li></ul><p>Major indexers:</p><ul><li><strong>Helius</strong>: most popular cNFT indexer</li><li><strong>Triton One</strong>: similar</li><li><strong>Custom indexers</strong>: large operators run own</li></ul><p>Якщо all indexers down → cNFTs effectively invisible (data on-chain still valid, just hard access). Compare standard NFT: anyone can query account directly.</p><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><p><strong>Gaming</strong>: millions of in-game items</p><ul><li>Sandbox-style metaverse assets</li><li>Card collections (TCG-style)</li><li>Item drops у MMOs</li></ul><p><strong>Loyalty</strong>: brand rewards</p><ul><li>Coffee shop punch cards</li><li>Airline miles</li><li>Gaming achievement systems</li></ul><p><strong>Ticketing</strong>: events</p><ul><li>Concert tickets</li><li>Conference badges</li><li>Time-limited access tokens</li></ul><p><strong>Identity</strong>: badges, certificates</p><ul><li>Educational credentials</li><li>Conference attendance</li><li>Membership proofs</li></ul><h2 id="operator-implications" tabindex="-1">Operator implications <a class="header-anchor" href="#operator-implications" aria-label="Permalink to &quot;Operator implications&quot;">​</a></h2><p>For validators: cNFT operations look like normal TXs (just specific programs called). No validator-side handling needed.</p><p>For RPC nodes: indexer integration valuable revenue stream (Helius makes значну часть income з cNFT indexing).</p><h2 id="marketplaces-support" tabindex="-1">Marketplaces support <a class="header-anchor" href="#marketplaces-support" aria-label="Permalink to &quot;Marketplaces support&quot;">​</a></h2><p>Major Solana NFT marketplaces support cNFTs natively:</p><ul><li>Magic Eden</li><li>Tensor</li><li>Hyperspace</li><li>DRiP (large drops use compression by default)</li></ul><p>Listings, trades, royalties same UX as standard NFTs (abstracted by tooling).</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><p>LumLabs validator unaffected — same TX processing. If LumLabs ever runs RPC node — consider Helius/Triton partnership for cNFT indexer services.</p><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,44)),t(r,{data:s}),e[1]||(e[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#s"><code>State compression</code></a>, <a href="/glossary#c"><code>cNFT</code></a>, <a href="/glossary#c"><code>Compressed NFT</code></a>, <a href="/glossary#m"><code>Merkle tree</code></a>, <a href="/glossary#m"><code>Merkle proof</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://www.helius.dev/blog/compressed-nfts" target="_blank" rel="noreferrer">Helius: cNFT guide</a></li><li><a href="https://solana.com/developers/courses/state-compression" target="_blank" rel="noreferrer">Solana docs: State Compression</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-10/5-snapshot-mirror">← 5. Snapshot mirror</a> | <strong>Наступне:</strong> <a href="/module-10/7-oracles">7. Oracles →</a></p>',6))])}}});export{m as __pageData,u as default};
